snippets:
[
    // 1. 自动进入数学环境 (全局生效)
    {trigger: "mk", replacement: "$$0$", options: "tA"},
    {trigger: "dm", replacement: "$$\n$0\n$$", options: "tAw"},

    // 2. 极速上下标 (单键级触发)
    {trigger: "sr", replacement: "^{2}", options: "mA"},
    {trigger: "cb", replacement: "^{3}", options: "mA"},
    {trigger: "inv", replacement: "^{-1}", options: "mA"},
    {trigger: "__", replacement: "_{$0}", options: "mA"},
    {trigger: "^^", replacement: "^{$0}", options: "mA"},

    // 3. CS & 逻辑专用符号
    {trigger: "=>", replacement: "\\implies", options: "mA"},
    {trigger: "=<", replacement: "\\impliedby", options: "mA"},
    {trigger: "iff", replacement: "\\iff", options: "mA"},
    {trigger: "!=", replacement: "\\neq", options: "mA"},
    {trigger: "==", replacement: "&\\mkern-0mu=", options: "mA"},
    {trigger: "OO", replacement: "\\mathcal{O}($0)", options: "mA"}, // 算法复杂度
    {trigger: "EE", replacement: "\\exists", options: "mA"},
    {trigger: "AA", replacement: "\\forall", options: "mA"},

    // 4. 高频数学结构
    {trigger: "ff", replacement: "\\frac{$0}{$1}", options: "mA"},
    {trigger: "sq", replacement: "\\sqrt{$0}", options: "mA"},
    {trigger: "sum", replacement: "\\sum_{n=${0:1}}^{${1:\\infty}} ${2:a_n z^n}", options: "mA"},
    {trigger: "lim", replacement: "\\lim_{${0:n} \\to ${1:\\infty}} ", options: "mA"},

    // 5. 括号自动配对并放大 (\left \right)
    {trigger: "((", replacement: "\\left( $0 \\right)", options: "mA"},
    {trigger: "[[", replacement: "\\left[ $0 \\right]", options: "mA"},
    {trigger: "{{", replacement: "\\left\\{ $0 \\right\\}", options: "mA"},

    // 6. 希腊字母速打 (用 @ 作为前缀)
    {trigger: "@a", replacement: "\\alpha", options: "mA"},
    {trigger: "@b", replacement: "\\beta", options: "mA"},
    {trigger: "@d", replacement: "\\delta", options: "mA"},
    {trigger: "@D", replacement: "\\Delta", options: "mA"},
    {trigger: "@t", replacement: "\\theta", options: "mA"},
    // 1. 基础矩阵环境 (手动填入内容)
    // 输入 bmat -> 方括号矩阵; pmat -> 圆括号矩阵; vmat -> 行列式
    {trigger: "bmat", replacement: "\\begin{bmatrix}\n$0\n\\end{bmatrix}", options: "mA"},
    {trigger: "pmat", replacement: "\\begin{pmatrix}\n$0\n\\end{pmatrix}", options: "mA"},
    {trigger: "vmat", replacement: "\\begin{vmatrix}\n$0\n\\end{vmatrix}", options: "mA"},
    {trigger: "case", replacement: "\\begin{cases}\n$0\n\\end{cases}", options: "mA"},

    // 2. 矩阵内部快捷操作 (极速填表)
    // 在矩阵内部输入 ,, 自动跳转到下一个单元格 (&)
    // 在矩阵内部输入 ;; 自动跳转到下一行 (\\)
    {trigger: ",,", replacement: " & ", options: "mA"},
    {trigger: ";;", replacement: " \\\\\n", options: "mA"},

    // 3. 【神级】正则动态矩阵 (自动生成行列)
    // 用法：输入 mat2x2 -> 自动出 2x2 矩阵; 输入 mat3x4 -> 自动出 3x4 矩阵
    {
    // 修改点：把中间的 x 改成了 [x*×] 匹配集
    trigger: /mat(\d)[x*×](\d)/, 
    replacement: (match) => {
        const rows = parseInt(match[1]);
        const cols = parseInt(match[2]);
        let matrix = "\\begin{bmatrix}\n";
        for (let i = 0; i < rows; i++) {
            let row = Array(cols).fill("$0").join(" & ");
            matrix += "  " + row + (i === rows - 1 ? "\n" : " \\\\\n");
        }
        matrix += "\\end{bmatrix}";
        return matrix;
    },
    options: "rmA"
},

    // 4. 常用特殊矩阵简写
    {trigger: "idmat", replacement: "\\begin{bmatrix} 1 & 0 \\\\ 0 & 1 \\end{bmatrix}", options: "mA"}, // 2x2单位阵
    {trigger: "zero", replacement: "\\mathbf{0}", options: "mA"}, // 零矩阵
]
